%[text] ## Newly Added TODO5
% Newly Added TODO5
data = load("grades.txt");
vec = extract_nozeros(data);

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

function vec = extract_nozeros(mat)
    [rows, ~] = size(mat);
    vec = [0, 0, 0, 0, 0];
    j = 0;
    for i=1:rows
        if (mat(i, i) ~= 0 && j<5)
            j = j + 1;
            vec(j) = mat(i,i);
        end
    end
end

